package github.chains;

import com.github.javaparser.StaticJavaParser;
import com.github.javaparser.ast.CompilationUnit;
import com.github.javaparser.ast.body.MethodDeclaration;
import com.github.javaparser.ast.expr.*;
import com.github.javaparser.ast.nodeTypes.NodeWithStatements;
import com.github.javaparser.ast.stmt.*;

import java.io.File;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Paths;
import java.util.ArrayList;
import java.util.List;

public class Main {
    public static void main(String[] args) throws IOException {
        if (args.length < 1) {
            System.err.println("Usage: java Main <path-to-java-file>");
            System.exit(1);
        }

        String filePath = args[0];
        File file = new File(filePath);

        CompilationUnit cu = StaticJavaParser.parse(file);

        cu.findAll(MethodDeclaration.class).forEach(method -> {
            if ("flyway".equals(method.getNameAsString())) {
                transformFlywayMethod(method);
            }
        });

        Files.write(Paths.get(filePath), cu.toString().getBytes());
        System.out.println("Transformation complete: " + filePath);
    }

    private static void transformFlywayMethod(MethodDeclaration method) {
        List<Statement> statementsToRemove = new ArrayList<>();
        Statement newStatement = null;

        if (method.getBody().isPresent()) {
            List<Statement> statements = method.getBody().get().getStatements();

            VariableDeclarationExpr flywayVarDecl = null;
            int flywayVarDeclIndex = -1;
            List<Expression> builderArgs = new ArrayList<>();

            for (int i = 0; i < statements.size(); i++) {
                Statement stmt = statements.get(i);

                if (stmt instanceof VariableDeclarationExpr) {
                    VariableDeclarationExpr varDecl = (VariableDeclarationExpr) stmt;
                    for (VariableDeclarator var : varDecl.getVariables()) {
                        if (var.getInitializer().isPresent() && 
                            var.getInitializer().get() instanceof ObjectCreationExpr) {
                            ObjectCreationExpr creation = (ObjectCreationExpr) var.getInitializer().get();
                            if ("Flyway".equals(creation.getType().asString())) {
                                flywayVarDecl = varDecl;
                                flywayVarDeclIndex = i;
                                break;
                            }
                        }
                    }
                }

                if (flywayVarDecl != null && stmt instanceof ExpressionStmt) {
                    ExpressionStmt exprStmt = (ExpressionStmt) stmt;
                    Expression expr = exprStmt.getExpression();
                    if (expr instanceof MethodCallExpr) {
                        MethodCallExpr methodCall = (MethodCallExpr) expr;
                        if (methodCall.getScope().isPresent()) {
                            Expression scope = methodCall.getScope().get();
                            if (scope instanceof NameExpr && 
                                "flyway".equals(((NameExpr) scope).getNameAsString())) {
                                String methodName = methodCall.getNameAsString();
                                if (methodName.equals("setDataSource")) {
                                    builderArgs.add(methodCall.getArgument(0));
                                    statementsToRemove.add(stmt);
                                } else if (methodName.equals("setClassLoader")) {
                                    builderArgs.add(methodCall.getArgument(0));
                                    statementsToRemove.add(stmt);
                                } else if (methodName.equals("setLocations")) {
                                    builderArgs.add(methodCall.getArgument(0));
                                    statementsToRemove.add(stmt);
                                } else if (methodName.equals("setValidateOnMigrate")) {
                                    builderArgs.add(methodCall.getArgument(0));
                                    statementsToRemove.add(stmt);
                                }
                            }
                        }
                    }
                }

                if (stmt instanceof ReturnStmt) {
                    ReturnStmt returnStmt = (ReturnStmt) stmt;
                    if (returnStmt.getExpression().isPresent() &&
                        returnStmt.getExpression().get() instanceof NameExpr) {
                        NameExpr returnExpr = (NameExpr) returnStmt.getExpression().get();
                        if ("flyway".equals(returnExpr.getNameAsString())) {
                            newStatement = new ReturnStmt(
                                new MethodCallExpr(
                                    new MethodCallExpr(
                                        new MethodCallExpr(
                                            new MethodCallExpr(
                                                new MethodCallExpr(
                                                    new NameExpr("Flyway"),
                                                    "configure"
                                                ),
                                                "dataSource",
                                                builderArgs.get(0)
                                            ),
                                            "classListLoader",
                                            builderArgs.get(1)
                                        ),
                                        "locations",
                                        builderArgs.get(2)
                                    ),
                                    "validateOnMigrate",
                                    builderArgs.get(3)
                                ),
                                "load"
                            );
                            statementsToRemove.add(stmt);
                        }
                    }
                }
            }

            if (flywayVarDecl != null && newStatement != null) {
                statementsToRemove.add(flywayVarDecl);

                for (Statement stmt : statementsToRemove) {
                    statements.remove(stmt);
                }

                statements.add(flywayVarDeclIndex, newStatement);
            }
        }
    }
}

