        prop.load(NisAppConfig.class.getClassLoader().getResourceAsStream("db.properties"));
        return Flyway.configure().dataSource(this.dataSource()).classListLoader(NisAppConfig.class.getClassLoader()).locations(prop.getProperty("flyway.locations")).validateOnMigrate(Boolean.valueOf(prop.getProperty("flyway.validate"))).load();
